// @ts-check

import { AbstractHandler } from './AbstractHandler.js'

/**
 * @typedef {import('../../utils/Command.js').Command} Command
 */

class ArraySetItemHandler extends AbstractHandler {
    requiredParametersCount = 3

    constructor() {
        super()
    }

    /**
     * @param {Command} command
     */
    process(command) {
        try {
            this.validate(command, this.requiredParametersCount, this.constructor.name)

            let data = command.payload[0]
            let indexes_from_payload = command.payload[1]
            let value = command.payload[2]

            /** @type {number[]} */
            let indexes
            if (Array.isArray(indexes_from_payload)) {
                indexes = indexes_from_payload
            } else {
                indexes = [indexes_from_payload]
            }

            if (indexes.length === 1) {
                // one-dimensional data
                data[indexes[0]] = value
            } else {
                // multi-dimensional data
                for (let i = 0; i < indexes.length - 1; i++) {
                    data = data[indexes[i]]
                }
                data[indexes[indexes.length - 1]] = value
            }

            return data
        } catch (error) {
            throw this.process_stack_trace(error, this.constructor.name)
        }
    }
}

export { ArraySetItemHandler }
